// ==========================================
// Prepare text array for batch embeddings:
// [new issue, past issue 1, past issue 2, ...]
// ==========================================
const newIssue = $('Extract Issue Info').item.json;
const response = $input.first().json;
const pastIssues = Array.isArray(response) ? response : (response.body || []);

// New issue text (first in array)
const texts = [
  (newIssue.issue_title + '\n' + (newIssue.issue_body || '')).substring(0, 2000)
];
const metadata = [{ is_new: true }];

// Past issues (exclude the new issue itself if present)
for (const issue of pastIssues) {
  if (issue.number === newIssue.issue_number) continue;
  if (issue.pull_request) continue; // skip PRs
  texts.push(
    (issue.title + '\n' + (issue.body || '').substring(0, 500)).substring(0, 2000)
  );
  metadata.push({
    is_new: false,
    number: issue.number,
    title: issue.title,
    html_url: issue.html_url,
    state: issue.state
  });
}

return [{ json: { texts, metadata, new_issue: newIssue } }];

// ==========================================
// Cosine similarity: new issue vs each past issue
// Find the max to detect duplicate
// ==========================================
function cosine(a, b) {
  let dot = 0, magA = 0, magB = 0;
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    magA += a[i] * a[i];
    magB += b[i] * b[i];
  }
  return dot / (Math.sqrt(magA) * Math.sqrt(magB));
}

const embedResp = $input.first().json;
const embeddings = embedResp.data;
const metadata = $('Prepare Texts for Embedding').item.json.metadata;
const newIssue = $('Prepare Texts for Embedding').item.json.new_issue;
const threshold = $('Set Configuration').item.json.duplicate_threshold || 0.85;

if (!embeddings || embeddings.length < 2) {
  // No past issues to compare against
  return [{
    json: {
      ...newIssue,
      max_similarity: 0,
      is_duplicate: false,
      matched_issue: null
    }
  }];
}

const newVec = embeddings[0].embedding;
let maxSim = 0;
let matched = null;

for (let i = 1; i < embeddings.length; i++) {
  const sim = cosine(newVec, embeddings[i].embedding);
  if (sim > maxSim) {
    maxSim = sim;
    matched = metadata[i];
  }
}

return [{
  json: {
    ...newIssue,
    max_similarity: Math.round(maxSim * 1000) / 1000,
    is_duplicate: maxSim >= threshold,
    matched_issue: matched
  }
}];

